void RooDalitzBS::DPTerms() const//Double_t &Rsum, Double_t &Rdif, TComplex &RInterf) {
{
  // Evaluate |A|^2 +/- |Abar|^2 term in the B0-B0bar time-evolution equation. 
  _Rsum = 0;
  _RInterf = 0;
  //double Rsum(0), Rdif(0);
  //TComplex RInterf(0);
  if(!kine_limits(_mhh))   return;
  if(fabs(_cosH)>1||fabs(_coshh)>1) return;  
  double m2pp = _mhh*_mhh;
  double xeff;
  xeff = efficiency(_mhh,_coshh,_cosH,_chi);//efficiency(_mhh,_coshh)*effcosH(m2p

  if( nacc<2 ){ cout<<" angular efficiency "<<xeff<<" "<<endl; nacc++; }
//  if(_mhh<1.2) xeff = 0.0;
//  double xeff = efficiency(_mhh,_coshh)*effcosH(m2pp, _cosH)*effchi(m2pp,_chi);
  double pB = getpB(_mhh);
  double pR = getpR(_mhh);
  double effphsp = pR*pB*xeff;

  if( isPhspRes ){
     _Rsum = effphsp;
     return;
  }

  Jpsihh_dlz *xdlz = new Jpsihh_dlz();
  //std::cout << "_Rsum _Rdif _RInterf " << _Rsum << " " << _Rdif << " " << _RInterf << std::endl;
  filldlz(*xdlz, _mhh, _coshh);
  TComplex H0(0), Hp(0), Hm(0);
  TComplex H0bar(0), Hpbar(0), Hmbar(0);
  amplitude(0,*xdlz, H0, H0bar);
  amplitude(1,*xdlz, Hp, Hpbar);
  amplitude(-1,*xdlz, Hm, Hmbar);
  double R = Rate(H0, Hp, Hm, _cosH, _chi);
  double Rbar = Rate(H0bar, Hpbar, Hmbar, _cosH, _chi);

  _Rsum = 0.5*(R+Rbar)* effphsp;
  _RInterf = InterfRate(H0, Hp, Hm, H0bar, Hpbar, Hmbar, _cosH, _chi)
      *effphsp *TComplex(cos(-1.0*_phis),sin(-1.0*_phis)) ;
      
  //std::cout << "_Rsum _Rdif _RInterf " << _Rsum << " " << _Rdif << " " << _RInterf << std::endl;
  delete xdlz;
}

