void RooDalitzBS::DPTermsIntegral() const
{
  CalCoupling();
// if(1) {
  if(checkchange()) {
//    std::cout << "Changed " << std::endl;
    DPTermsIntegralMethod1();
  } else {
    int nr = _resList->GetSize();
    
    double hx = (dlz_hx-dlz_lx)/2./np_dlzx;
    double hy = (dlz_hy-dlz_ly)/2./(np_dlzy);
  
    double RsumInt(0);
    TComplex RInterfInt = TComplex(0);
    for(int ir1=0; ir1<nr; ++ir1) {
      for(int ir2=0; ir2<nr; ++ir2) {
        for(int ih=0; ih<3; ++ih) {
          RsumInt += (0.5*HH[ih][ir1][ir2]*
                          (HHR[ir1][ih]*TComplex::Conjugate(HHR[ir2][ih])
                           +HHRbar[ir1][ih]*TComplex::Conjugate(HHRbar[ir2][ih]))).Re();  
          RInterfInt +=  HH[ih][ir1][ir2] * HHRbar[ir1][ih]*TComplex::Conjugate(HHR[ir2][ih]);   
        }
        RsumInt += (0.5*HH[3][ir1][ir2]*
                        (HHR[ir1][2]*TComplex::Conjugate(HHR[ir2][0])
                         +HHRbar[ir1][2]*TComplex::Conjugate(HHRbar[ir2][0]))).Re();  
        RInterfInt +=  0.5*HH[3][ir1][ir2] *HHRbar[ir1][2]*TComplex::Conjugate(HHR[ir2][0])
          +0.5*TComplex::Conjugate(HH[3][ir1][ir2]*HHR[ir1][2]*TComplex::Conjugate(HHRbar[ir2][0]));
        //HH[3][ir1][ir2])*HHRbar[ir1][0]*TComplex::Conjugate(HHRbar[ir2][2]));
      }
    }
    _RsumInt = RsumInt * hx*hy;
    _RInterfInt = RInterfInt *hx*hy*TComplex(cos(-1.0*_phis),sin(-1.0*_phis));
    
  }
  
 //update cached resparam
  int ir(0);
  TIterator* coefIter=_resList->MakeIterator();
  while(RooArgList* Ires = (RooArgList*)coefIter->Next()) {
    RooArgList ires = (*Ires);
    int type = (int)((RooAbsReal&)ires[ires.getSize()-1]).getVal();
    double m0 = 0;
    double g0 = 0;
    double rg = 0;

    if(type==1) { //breit wigner
      m0 = ((RooAbsReal&)ires[ires.getSize()-4]).getVal();
      g0 = ((RooAbsReal&)ires[ires.getSize()-3]).getVal();
    } else if(type==2) { //f0 flatte
      m0 = ((RooAbsReal&)ires[2]).getVal();
      g0 = ((RooAbsReal&)ires[3]).getVal();
      rg = ((RooAbsReal&)ires[4]).getVal();
    } else if(type==10) {//spline
//       std::cout << "SP par" << std::endl;
       for(int it3=0; it3<ires.getSize(); ++it3) {
          _resSpnCache[it3] = ((RooAbsReal&)ires[it3]).getVal();
//          std::cout << _resSpnCache[it3] << std::endl;
       }
    }
    _resParCache[3*ir+0] = m0;
    _resParCache[3*ir+1] = g0;
    _resParCache[3*ir+2] = rg;
    ir++;
  }
  delete coefIter;
}

//Integration of m(hh) and coshh; already integral over chi and cosH in RateIntegral
void RooDalitzBS::DPTermsIntegralMethod1() const
{
  //TComplex HH[4][MYRN][MYRN];
  int nr = _resList->GetSize();
  for(int ir1=0; ir1<nr; ++ir1) {
    for(int ir2=0; ir2<nr; ++ir2) {
      for(int ih=0; ih<4; ++ih){
        HH[ih][ir1][ir2] = 0.0;
      }
    }  
  }
  double hx = (dlz_hx-dlz_lx)/2./np_dlzx;
  double hy = (dlz_hy-dlz_ly)/2./(np_dlzy);
  
  int ng = pdlz->size();
  double RsumInt = 0;
  TComplex RInterfInt = TComplex(0);
  TComplex AAbarstar;
  
  double R, Rbar;
  for(int ig = 0; ig<ng; ++ig) {
    Jpsihh_dlz &p = *(*pdlz)[ig];
//    Jpsihh_dlz p = pdlz[ig];
    TComplex H0(0), Hp(0), Hm(0);
    TComplex H0bar(0), Hpbar(0), Hmbar(0);
    amplitude(0,p, H0, H0bar);
    amplitude(1,p, Hp, Hpbar);
    amplitude(-1,p, Hm, Hmbar);
//    if(ig==0) printf("\n check cached pdlz %10.6f %10.6f",  p.dre[0][1], p.dre[1][1]);
    R = RateIntegral(H0, Hp, Hm, p);
    Rbar = RateIntegral(H0bar, Hpbar, Hmbar, p);
    AAbarstar = InterfRateIntegral(H0,Hp,Hm,H0bar,Hpbar, Hmbar, p);
    /*
    
    double xeff = 1.0;
//  if(p.mpp<1.2) xeff = 0.0;
    if(p.mpp>dlz_hy) xeff *= hr;
    double effphsp = pR*pB*xeff;
    */
    double effphsp = p.phsp;
    RsumInt += 0.5*(R+Rbar)*effphsp;
    RInterfInt += AAbarstar*effphsp;  

    for(int ir1=0; ir1<nr; ++ir1) {
      for(int ir2=0; ir2<nr; ++ir2) {
        for(int ih=0; ih<=2; ++ih) {
          int iI = 1;
          if(ih==1) iI = 0;
          HH[ih][ir1][ir2] += effphsp*TComplex(p.dre[ir1][ih],p.dim[ir1][ih]) *
            TComplex::Conjugate(TComplex(p.dre[ir2][ih],p.dim[ir2][ih])) * p.Inte[iI];
        }
      }  
    }
    for(int ir1=0; ir1<nr; ++ir1) {
      for(int ir2=0; ir2<nr; ++ir2) {
        int iI = 2;
        HH[3][ir1][ir2] += effphsp*TComplex(p.dre[ir1][2],p.dim[ir1][2]) *
          TComplex::Conjugate(TComplex(p.dre[ir2][0],p.dim[ir2][0])) * p.Inte[iI];
      }
    }  
  }
 
  
  _RsumInt = RsumInt * hx*hy;
  _RInterfInt = RInterfInt *hx*hy*TComplex(cos(-1.0*_phis),sin(-1.0*_phis));
  
 
}

void RooDalitzBS::getInt(double *v0int, double *vlint, double *veint, Bool_t force, double ylo, double yhi) const
{
  int nres = _resList->GetSize();
  double a0[21],al[21],ae[21];
  double A0[21],Al[21],Ae[21];
  for(int i=0; i<21; ++i) {
    a0[i] = 0;
    al[i] = 0;
    ae[i] = 0;
    A0[i] = 0;
    Al[i] = 0;
    Ae[i] = 0;
  }
  
  double hx = (dlz_hx-dlz_lx)/2./np_dlzx;
  double hy = (dlz_hy-dlz_ly)/2./(np_dlzy);
  
  int ng = pdlz->size();
  CalCoupling(); 
  for(int ig = 0; ig<ng; ++ig) {
    Jpsihh_dlz &p = *(*pdlz)[ig];
    if(!(p.mpp>ylo&&p.mpp<yhi)) continue;
    Amplitude(0,p, &a0[0], force);
    Amplitude(1,p, &al[0], force);
    Amplitude(-1,p, &ae[0], force);

    double pB = getpB(p.mpp);
    double pR = getpR(p.mpp);
    
    double xeff = 1.0;
        
//    xeff = efficiency(p.mpp,p.cospp);
/*  double m2pp = p.mpp*p.mpp;
    Double_t I1 = effcosHIntegral(m2pp, 1);
    Double_t I2 = effcosHIntegral(m2pp, 2);
*/
    double effphsp = pR*pB*xeff;
  
    for(int i=0; i<=nres; ++i) {
      A0[i] += a0[i]*effphsp;//*I1;
      Al[i] += al[i]*effphsp;//*I2;
      Ae[i] += ae[i]*effphsp;//*I2;
    }
  }
  
  double sum = A0[0]+Al[0]+Ae[0];  
//  std::cout<<< "sum int " << sum << std::endl;
  for(int k=1; k<=nres;++k) {
      v0int[k-1] = A0[k]/sum;
      vlint[k-1] = Al[k]/sum;
      veint[k-1] = Ae[k]/sum;
  }
  
}

void RooDalitzBS::getIntf(double *v0int, double *vlint, double *veint, Bool_t force, double ylo, double yhi) const
{
  int nres = _resList->GetSize();
  int ninf = nres*(nres-1)/2;
  
  double a0[55],al[55],ae[55];
  double A0[55],Al[55],Ae[55];
  for(int i=0; i<55; ++i) {
    a0[i] = 0;
    al[i] = 0;
    ae[i] = 0;
    A0[i] = 0;
    Al[i] = 0;
    Ae[i] = 0;
  }
    CalCoupling(); 
  double hx = (dlz_hx-dlz_lx)/2./np_dlzx;
  double hy = (dlz_hy-dlz_ly)/2./(np_dlzy);
  
  int ng = pdlz->size();
 
  for(int ig = 0; ig<ng; ++ig) {
    Jpsihh_dlz &p = *(*pdlz)[ig];
    if(!(p.mpp>ylo&&p.mpp<yhi)) continue;
    Interfer(0,p, &a0[0], force);
    Interfer(1,p, &al[0], force);
    Interfer(-1,p, &ae[0], force);

    double pB = getpB(p.mpp);
    double pR = getpR(p.mpp);
    
    double xeff = 1.0;
        
//    xeff = efficiency(p.mpp,p.cospp);
/*  double m2pp = p.mpp*p.mpp;
    Double_t I1 = effcosHIntegral(m2pp, 1);
    Double_t I2 = effcosHIntegral(m2pp, 2);
*/
    double effphsp = pR*pB*xeff;
  
    for(int i=0; i<=ninf; ++i) {
      A0[i] += a0[i]*effphsp;//*I1;
      Al[i] += al[i]*effphsp;//*I2;
      Ae[i] += ae[i]*effphsp;//*I2;
    }
  }
  
  double sum = A0[0]+Al[0]+Ae[0];  
  //std::cout<<< "sum int " << sum << std::endl;  
  for(int k=1; k<=ninf;++k) {
      v0int[k-1] = A0[k]/sum;
      vlint[k-1] = Al[k]/sum;
      veint[k-1] = Ae[k]/sum;
  }
  
}


